"""experiment.py v2 — generated by experiment-plan (revision 2).

Topic: Trust-Aware Context Selection on HotpotQA (distractor setting).
Revision 2 adds: entity-overlap authority signal, Learned-TrustScore logistic
regression, score-gap diagnostic, 1/3-2/3 train/test split per seed.
"""
import os, json, time, pathlib, random, re, statistics

try:
    import modal
    _HAS_MODAL = True
except Exception:
    _HAS_MODAL = False

APP_NAME = "paper-experiment-94d7"
VOL_NAME = "paper-outputs-20260422-100735-94d7"

if _HAS_MODAL:
    image = (
        modal.Image.debian_slim(python_version="3.11")
        .pip_install(
            "datasets>=2.14",
            "numpy",
            "scikit-learn",
            "rank-bm25",
            "sentence-transformers",
            "tqdm",
        )
    )
    app = modal.App(APP_NAME, image=image)
    vol = modal.Volume.from_name(VOL_NAME, create_if_missing=True)


_ENTITY_RE = re.compile(r"\b[A-Z][A-Za-z0-9]+(?:\s+[A-Z][A-Za-z0-9]+)*\b")
_NUM_RE = re.compile(r"\b\d{2,}\b")
_STOP = {"the", "a", "an", "and", "or", "but", "of", "in", "on", "at", "to", "is", "are", "was", "were"}


def _parse_context(ctx):
    if isinstance(ctx, dict):
        return list(ctx["title"]), list(ctx["sentences"])
    titles = [c[0] for c in ctx]
    sents = [c[1] for c in ctx]
    return titles, sents


def _parse_supporting(sf):
    if isinstance(sf, dict):
        return list(zip(sf["title"], sf["sent_id"]))
    return [(t, i) for t, i in sf]


def _extract_entity_tokens(text: str):
    ents = {m.group(0).lower() for m in _ENTITY_RE.finditer(text)}
    ents = {e for e in ents if len(e) >= 3 and e not in _STOP}
    ents |= {m.group(0) for m in _NUM_RE.finditer(text)}
    return ents


def _load_subset(seed: int, subset_size: int = 300):
    from datasets import load_dataset
    ds = load_dataset("hotpotqa/hotpot_qa", "distractor", split="validation")
    idx = list(range(len(ds)))
    random.Random(seed).shuffle(idx)
    return [ds[i] for i in idx[:subset_size]]


def _extract_features(examples, sbert):
    import numpy as np
    from rank_bm25 import BM25Okapi
    from sklearn.feature_extraction.text import TfidfVectorizer
    from sklearn.metrics.pairwise import cosine_similarity

    out = []
    for ex in examples:
        titles, sents_list = _parse_context(ex["context"])
        gold_pairs = set(_parse_supporting(ex["supporting_facts"]))
        gold_titles = {t for t, _ in gold_pairs}
        paragraphs = [" ".join(s) for s in sents_list]
        q = ex["question"]
        gold_mask = np.array([1 if t in gold_titles else 0 for t in titles])
        if int(gold_mask.sum()) != 2 or len(paragraphs) < 2:
            continue

        tok = [p.lower().split() for p in paragraphs]
        bm = BM25Okapi(tok)
        bm25_scores = np.array(bm.get_scores(q.lower().split()))

        vec = TfidfVectorizer().fit([q] + paragraphs)
        qv = vec.transform([q]); pv = vec.transform(paragraphs)
        tfidf_scores = cosine_similarity(qv, pv).ravel()

        q_emb = sbert.encode(q, normalize_embeddings=True)
        p_embs = sbert.encode(paragraphs, normalize_embeddings=True)
        sbert_scores = (p_embs @ q_emb).ravel()

        lens = np.array([len(p.split()) for p in paragraphs], dtype=float)
        logl = np.log(lens + 1.0)

        sim_mat = p_embs @ p_embs.T
        np.fill_diagonal(sim_mat, 0.0)
        consistency = sim_mat.sum(axis=1) / max(1, (len(paragraphs) - 1))

        q_ents = _extract_entity_tokens(q)
        p_ents = [_extract_entity_tokens(p) for p in paragraphs]
        if q_ents:
            entity_overlap = np.array([len(q_ents & pe) / len(q_ents) for pe in p_ents])
        else:
            entity_overlap = np.zeros(len(paragraphs))

        def _norm(a):
            a = np.asarray(a, dtype=float)
            rng = a.max() - a.min()
            return (a - a.min()) / (rng + 1e-8)

        F = np.stack([
            _norm(sbert_scores),
            _norm(bm25_scores),
            _norm(tfidf_scores),
            _norm(logl),
            _norm(consistency),
            _norm(entity_overlap),
        ], axis=1)

        out.append({
            "features": F,
            "gold_mask": gold_mask,
            "sbert_scores": np.asarray(sbert_scores),
            "bm25_scores": np.asarray(bm25_scores),
            "tfidf_scores": np.asarray(tfidf_scores),
            "entity_overlap": np.asarray(entity_overlap),
            "logl": logl,
            "consistency": consistency,
            "titles": titles,
            "sents_list": sents_list,
            "gold_pairs": gold_pairs,
        })
    return out


def _eval_method(scores_list, feats_list):
    import numpy as np
    p_at_2 = 0
    para_f1_sum = 0.0
    sup_f1_sum = 0.0
    gold_sum = 0.0; gold_n = 0
    dist_sum = 0.0; dist_n = 0
    n = 0
    for scores, feat in zip(scores_list, feats_list):
        gold_mask = feat["gold_mask"]
        titles = feat["titles"]
        sents_list = feat["sents_list"]
        gold_pairs = feat["gold_pairs"]
        gold_idx = {int(i) for i in np.where(gold_mask == 1)[0].tolist()}

        s = np.asarray(scores, dtype=float)
        top2 = set(np.argsort(-s)[:2].tolist())
        if top2 == gold_idx:
            p_at_2 += 1
        tp = len(top2 & gold_idx)
        fp = len(top2 - gold_idx)
        fn = len(gold_idx - top2)
        f1 = 0.0 if tp == 0 else (2 * tp) / (2 * tp + fp + fn)
        para_f1_sum += f1

        pred_sent_pairs = set()
        for pi in top2:
            t = titles[pi]
            for si in range(len(sents_list[pi])):
                pred_sent_pairs.add((t, si))
        tp_s = len(pred_sent_pairs & gold_pairs)
        fp_s = len(pred_sent_pairs - gold_pairs)
        fn_s = len(gold_pairs - pred_sent_pairs)
        f1_s = 0.0 if tp_s == 0 else (2 * tp_s) / (2 * tp_s + fp_s + fn_s)
        sup_f1_sum += f1_s

        gold_sum += float(s[gold_mask == 1].sum())
        dist_sum += float(s[gold_mask == 0].sum())
        gold_n += int((gold_mask == 1).sum())
        dist_n += int((gold_mask == 0).sum())
        n += 1

    gap = (gold_sum / gold_n - dist_sum / dist_n) if gold_n and dist_n else 0.0
    return {
        "p_at_2": p_at_2 / n if n else 0.0,
        "paragraph_f1": para_f1_sum / n if n else 0.0,
        "supporting_fact_f1": sup_f1_sum / n if n else 0.0,
        "score_gap_gold_minus_distractor": gap,
        "n_examples": n,
    }


def _score_methods(examples, seed: int):
    import numpy as np
    from sklearn.linear_model import LogisticRegression
    from sentence_transformers import SentenceTransformer

    rng = random.Random(seed)
    sbert = SentenceTransformer("sentence-transformers/all-MiniLM-L6-v2")

    feats = _extract_features(examples, sbert)
    if not feats:
        return {}

    train_k = max(1, len(feats) // 3)
    perm = list(range(len(feats)))
    rng.shuffle(perm)
    train_feats = [feats[i] for i in perm[:train_k]]
    test_feats = [feats[i] for i in perm[train_k:]]

    X_train = np.concatenate([f["features"] for f in train_feats], axis=0)
    y_train = np.concatenate([f["gold_mask"] for f in train_feats], axis=0)
    lr = LogisticRegression(max_iter=1000, C=1.0)
    lr.fit(X_train, y_train)
    feat_names = ["sbert_rel", "bm25", "tfidf", "log_len", "consistency", "entity_overlap"]
    lr_weights = dict(zip(feat_names, lr.coef_[0].tolist()))
    lr_intercept = float(lr.intercept_[0])

    methods = ["random", "bm25", "tfidf", "sbert", "entity_overlap", "trust_uniform", "trust_learned"]
    score_lists = {m: [] for m in methods}

    for f in test_feats:
        n = len(f["gold_mask"])
        perm2 = list(range(n)); rng.shuffle(perm2)
        score_lists["random"].append(np.array([n - perm2.index(i) for i in range(n)], dtype=float))
        score_lists["bm25"].append(f["bm25_scores"])
        score_lists["tfidf"].append(f["tfidf_scores"])
        score_lists["sbert"].append(f["sbert_scores"])
        score_lists["entity_overlap"].append(f["entity_overlap"])
        F = f["features"]
        trust_u = (F[:, 0] + F[:, 3] + F[:, 4]) / 3.0
        score_lists["trust_uniform"].append(trust_u)
        trust_l = lr.predict_proba(F)[:, 1]
        score_lists["trust_learned"].append(trust_l)

    per_method = {m: _eval_method(score_lists[m], test_feats) for m in methods}
    per_method["_lr_weights"] = lr_weights
    per_method["_lr_intercept"] = lr_intercept
    per_method["_train_size"] = len(train_feats)
    per_method["_test_size"] = len(test_feats)
    return per_method


def _run_one_seed(seed: int, subset_size: int, out_dir: pathlib.Path) -> dict:
    t0 = time.time()
    examples = _load_subset(seed, subset_size=subset_size)
    per_method = _score_methods(examples, seed)
    dt = time.time() - t0
    primary = per_method["trust_learned"]["p_at_2"] if per_method else 0.0
    result = {
        "seed": seed,
        "primary_metric_name": "trust_learned_p_at_2",
        "primary_metric": primary,
        "training_time_s": dt,
        "peak_gpu_memory_gb": 0.0,
        "per_method": per_method,
        "subset_size": subset_size,
    }
    print(f"RESULT: metric={primary:.4f} seed={seed}")
    out_dir.mkdir(parents=True, exist_ok=True)
    (out_dir / f"metrics_seed{seed}.json").write_text(json.dumps(result, indent=2))
    return result


def _summarize(results):
    per_method_0 = results[0]["per_method"]
    methods = [m for m in per_method_0.keys() if not m.startswith("_")]
    agg = {}
    for m in methods:
        p = [r["per_method"][m]["p_at_2"] for r in results]
        f = [r["per_method"][m]["paragraph_f1"] for r in results]
        s = [r["per_method"][m]["supporting_fact_f1"] for r in results]
        g = [r["per_method"][m]["score_gap_gold_minus_distractor"] for r in results]
        agg[m] = {
            "p_at_2_mean": statistics.mean(p),
            "p_at_2_std": statistics.pstdev(p),
            "paragraph_f1_mean": statistics.mean(f),
            "paragraph_f1_std": statistics.pstdev(f),
            "supporting_fact_f1_mean": statistics.mean(s),
            "supporting_fact_f1_std": statistics.pstdev(s),
            "score_gap_mean": statistics.mean(g),
            "score_gap_std": statistics.pstdev(g),
        }
    weight_keys = list(per_method_0["_lr_weights"].keys())
    lr_agg = {k: {"mean": statistics.mean([r["per_method"]["_lr_weights"][k] for r in results]),
                  "std": statistics.pstdev([r["per_method"]["_lr_weights"][k] for r in results])}
              for k in weight_keys}

    primary = [r["primary_metric"] for r in results]
    mean = sum(primary) / len(primary)
    std = (sum((p - mean) ** 2 for p in primary) / len(primary)) ** 0.5
    return {
        "primary_metric": {"name": results[0]["primary_metric_name"], "mean": mean, "std": std, "n_seeds": len(primary)},
        "per_seed": results,
        "per_method_aggregate": agg,
        "lr_weights_aggregate": lr_agg,
    }


if _HAS_MODAL:
    @app.function(cpu=4.0, memory=8192, timeout=1800, volumes={"/outputs": vol})
    def run_seed(seed: int) -> dict:
        subset_size = int(os.environ.get("SUBSET_SIZE", "300"))
        out = pathlib.Path("/outputs")
        result = _run_one_seed(seed, subset_size, out)
        vol.commit()
        return result

    @app.local_entrypoint()
    def main(seeds: str = "0,1,2", subset_size: int = 300):
        os.environ["SUBSET_SIZE"] = str(subset_size)
        seed_list = [int(s) for s in seeds.split(",")]
        results = list(run_seed.map(seed_list))
        summary = _summarize(results)
        with vol.batch_upload() as up:
            up.put_bytes(json.dumps(summary, indent=2).encode(), "/summary.json")
        print(f"SUMMARY: {json.dumps(summary)}")


if __name__ == "__main__":
    out = pathlib.Path("experiment_logs"); out.mkdir(exist_ok=True)
    seed_list = [int(s) for s in os.environ.get("SEEDS", "0,1,2").split(",")]
    subset_size = int(os.environ.get("SUBSET_SIZE", "300"))
    results = [_run_one_seed(s, subset_size, out) for s in seed_list]
    summary = _summarize(results)
    (out / "summary.json").write_text(json.dumps(summary, indent=2))
    print(f"SUMMARY: {json.dumps(summary)}")
